"use client";

/**
 * CollapsibleFolder Section
 *
 * Generic collapsible folder section for organizing items in a grid layout.
 * Supports native HTML5 drag & drop with visual feedback, sorting, and folder management actions.
 *
 * ## Drag & Drop Features
 * - **Drop target visual state**: Folder highlights when dragging items over it
 * - **Insertion indicator**: Dynamic line shows exactly where the item will be inserted
 * - **Automatic state cleanup**: Visual feedback clears when drag ends or user leaves folder
 * - **Empty folder support**: Shows centered insertion line for empty folders
 * - **Collapsed folder support**: Accepts drops even when folder is collapsed
 *
 * ## Customization
 * Use `renderItem` to render your custom items. See CollapsibleFolder stories and AgentFolder for examples.
 */

import React, { useRef, useState } from "react";
import { useDroppable } from "@dnd-kit/core";
import type { CollapsibleFolderProps } from "./CollapsibleFolder.types";
import { Collapsible } from "../../components/Collapsible";
import { Dropdown } from "../../components/Dropdown";
import { Badge } from "../../components/Badge";
import { Button } from "../../components/Button";
import { ChevronDown, MoreHorizontal } from "lucide-react";
import styles from "./CollapsibleFolder.module.css";

export function CollapsibleFolder<
  TItem extends { id: string; draggable?: boolean },
>(props: CollapsibleFolderProps<TItem>) {
  const {
    id,
    title,
    itemCount,
    items,
    renderItem,
    itemLabel = "Item",
    itemLabelPlural = "Items",
    emptyText = "No items in this folder",
    sortLabel = "Sort",
    defaultExpanded = true,
    sortOptions,
    selectedSort,
    onSortChange,
    onDrop,
    onFolderEdit,
    onFolderDelete,
    onFolderInvite,
    isDropTarget = false,
    isDropCompleted = false,
    onDragEnter,
    onDragLeaveFolder,
    className,
    ...rest
  } = props;

  const [isExpanded, setIsExpanded] = useState(defaultExpanded);
  const [insertionIndex, setInsertionIndex] = useState<number | null>(null);
  const [isLocalDropTarget, setIsLocalDropTarget] = useState(false);
  const gridRef = useRef<HTMLDivElement>(null);
  const { setNodeRef } = useDroppable({ id });

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = "move";

    // Notify parent that drag is over this folder
    if (!isLocalDropTarget) {
      setIsLocalDropTarget(true);
      onDragEnter?.();
    }

    // Calculate insertion index based on cursor position
    if (!isExpanded || items.length === 0) {
      setInsertionIndex(0);
      return;
    }

    const gridEl = gridRef.current;
    if (!gridEl) return;

    const itemElements = Array.from(
      gridEl.querySelectorAll("[data-item-id]"),
    ) as HTMLElement[];
    const cursorY = e.clientY;
    let idx = itemElements.length;

    for (let i = 0; i < itemElements.length; i++) {
      const item = itemElements[i];
      if (!item) continue;
      const rect = item.getBoundingClientRect();
      if (cursorY < rect.top + rect.height / 2) {
        idx = i;
        break;
      }
    }

    setInsertionIndex(idx);
  };

  const handleDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
    if (!e.currentTarget.contains(e.relatedTarget as Node)) {
      setIsLocalDropTarget(false);
      setInsertionIndex(null);
      onDragLeaveFolder?.();
    }
  };

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    // Try "text/plain" first (from native drag), fallback to "itemId"
    const itemId =
      e.dataTransfer.getData("text/plain") || e.dataTransfer.getData("itemId");
    if (itemId && onDrop) {
      const index = insertionIndex ?? items.length;
      onDrop(itemId, id, index);
    }
    // Clean up drag state
    setIsLocalDropTarget(false);
    setInsertionIndex(null);
    onDragLeaveFolder?.();
  };

  const handleDragStart = (
    e: React.DragEvent<HTMLDivElement>,
    itemId: string,
  ) => {
    e.dataTransfer.effectAllowed = "move";
    e.dataTransfer.setData("text/plain", itemId);
  };

  // Build sort dropdown items
  const sortDropdownItems = sortOptions?.map((option) => ({
    id: option.value,
    label: option.label,
    onClick: () => onSortChange?.(option.value),
  }));

  // Build folder actions dropdown
  const folderActionsItems = [
    ...(onFolderEdit
      ? [
          {
            id: "rename",
            label: "Rename",
            onClick: onFolderEdit,
          },
        ]
      : []),
    ...(onFolderInvite
      ? [
          {
            id: "invite",
            label: "Invite participants",
            onClick: onFolderInvite,
          },
        ]
      : []),
    ...(onFolderDelete
      ? [
          {
            id: "delete",
            label: "Delete folder",
            danger: true,
            onClick: onFolderDelete,
          },
        ]
      : []),
  ];

  const isActiveDropTarget = isDropTarget || isLocalDropTarget;

  const classNames = [
    styles.folder,
    isActiveDropTarget && styles.dropTarget,
    isDropCompleted && styles.dropCompleted,
    className,
  ]
    .filter(Boolean)
    .join(" ");

  const itemLabelDisplay = itemCount === 1 ? itemLabel : itemLabelPlural;

  return (
    <div
      ref={setNodeRef}
      className={classNames}
      data-folder-id={id}
      data-drop-active={isActiveDropTarget}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      {...rest}
    >
      <Collapsible open={isExpanded} onOpenChange={setIsExpanded}>
        {/* Folder Header */}
        <div className={styles.header}>
          <Collapsible.Trigger className={styles.trigger}>
            <ChevronDown
              size={20}
              className={`${styles.chevron} ${isExpanded ? styles.expanded : ""}`}
            />
            <h2 className={styles.title}>{title}</h2>
            <Badge variant="secondary" className={styles.badge}>
              {itemCount}
              <span className={styles.badgeLabel}> {itemLabelDisplay}</span>
            </Badge>
          </Collapsible.Trigger>

          <div className={styles.actions}>
            {/* Sort dropdown */}
            {sortOptions && sortOptions.length > 0 && (
              <div className={styles.sortDropdown}>
                <Dropdown
                  trigger={
                    <Button
                      variant="ghost"
                      size="sm"
                      iconRight={<ChevronDown size={16} />}
                      aria-label={`Sort by ${sortLabel}`}
                    >
                      {sortOptions.find((opt) => opt.value === selectedSort)
                        ?.label || sortLabel}
                    </Button>
                  }
                  items={sortDropdownItems}
                  placement="bottom-end"
                />
              </div>
            )}

            {/* Folder actions menu */}
            {folderActionsItems.length > 0 && (
              <Dropdown
                trigger={
                  <Button
                    variant="ghost"
                    size="sm"
                    iconOnly
                    icon={<MoreHorizontal size={20} />}
                    aria-label="Folder actions"
                  />
                }
                items={folderActionsItems}
                placement="bottom-end"
              />
            )}
          </div>
        </div>

        {/* Items Grid */}
        <Collapsible.Content>
          <div className={styles.content}>
            {items.length === 0 ? (
              isActiveDropTarget ? (
                <div className={styles.emptyDropZone}>
                  <div className={styles.insertionLine} role="presentation" />
                </div>
              ) : (
                <div className={styles.emptyState}>
                  <p className={styles.emptyText}>{emptyText}</p>
                </div>
              )
            ) : (
              <div className={styles.grid} ref={gridRef}>
                {items.map((item, index) => (
                  <React.Fragment key={item.id}>
                    {isActiveDropTarget && insertionIndex === index && (
                      <div
                        className={styles.insertionLine}
                        role="presentation"
                      />
                    )}
                    <div
                      data-item-id={item.id}
                      draggable={item.draggable}
                      onDragStart={(e) => handleDragStart(e, item.id)}
                    >
                      {renderItem(item, index)}
                    </div>
                  </React.Fragment>
                ))}
                {isActiveDropTarget && insertionIndex === items.length && (
                  <div className={styles.insertionLine} role="presentation" />
                )}
              </div>
            )}
          </div>
        </Collapsible.Content>
      </Collapsible>
    </div>
  );
}

CollapsibleFolder.displayName = "CollapsibleFolder";

/**
 * CollapsibleFolder Section Types
 *
 * Type definitions for the CollapsibleFolder section - generic collapsible container
 * for organizing items with drag & drop support.
 */

import type { HTMLAttributes } from "react";

/**
 * Sort option for organizing items
 */
export interface SortOption {
  /**
   * Display label
   */
  label: string;

  /**
   * Internal value
   */
  value: string;
}

/**
 * CollapsibleFolder component props
 *
 * Generic folder component that can contain any type of items (agents, files, documents, etc.)
 * with drag & drop, sorting, and folder management features.
 *
 * @template TItem - The type of items in the folder. Must have `id` property and optional `draggable` boolean.
 *
 * @example
 * ```tsx
 * // With files
 * <CollapsibleFolder
 *   id="folder-1"
 *   title="Documents"
 *   itemCount={3}
 *   items={files}
 *   itemLabel="File"
 *   itemLabelPlural="Files"
 *   emptyText="No files in this folder"
 *   renderItem={(file) => <FileCard {...file} />}
 * />
 *
 * // With custom items
 * <CollapsibleFolder
 *   id="folder-2"
 *   title="Projects"
 *   itemCount={2}
 *   items={projects}
 *   itemLabel="Project"
 *   itemLabelPlural="Projects"
 *   renderItem={(project) => (
 *     <div>{project.name} - {project.status}</div>
 *   )}
 * />
 * ```
 */
export interface CollapsibleFolderProps<
  TItem extends { id: string; draggable?: boolean; [key: string]: any },
> extends Omit<HTMLAttributes<HTMLDivElement>, "onDrop"> {
  /**
   * Unique folder identifier
   */
  id: string;

  /**
   * Folder title/name
   */
  title: string;

  /**
   * Number of items in folder
   */
  itemCount: number;

  /**
   * Array of items to display
   */
  items: TItem[];

  /**
   * Render function for each item
   * @param item - The item to render
   * @param index - The item's index in the items array
   * @returns React node to render for this item
   */
  renderItem: (item: TItem, index: number) => React.ReactNode;

  /**
   * Singular label for items (used in badge)
   * @default "Item"
   */
  itemLabel?: string;

  /**
   * Plural label for items (used in badge)
   * @default "Items"
   */
  itemLabelPlural?: string;

  /**
   * Empty state message when folder contains no items
   * @default "No items in this folder"
   */
  emptyText?: string;

  /**
   * Fallback label for sort button
   * @default "Sort"
   */
  sortLabel?: string;

  /**
   * Default expanded state
   * @default true
   */
  defaultExpanded?: boolean;

  /**
   * Available sort options
   */
  sortOptions?: SortOption[];

  /**
   * Currently selected sort value
   */
  selectedSort?: string;

  /**
   * Sort option change handler
   */
  onSortChange?: (value: string) => void;

  /**
   * Drop handler for drag & drop
   * @param itemId - ID of the item being dropped
   * @param folderId - ID of the target folder
   * @param index - Position index where the item will be inserted (optional, defaults to end)
   */
  onDrop?: (itemId: string, folderId: string, index?: number) => void;

  /**
   * Rename folder handler
   */
  onFolderEdit?: () => void;

  /**
   * Delete folder handler
   */
  onFolderDelete?: () => void;

  /**
   * Invite participants to folder handler
   */
  onFolderInvite?: () => void;

  /**
   * Is this folder currently a valid drop target
   * @internal
   */
  isDropTarget?: boolean;

  /**
   * Briefly set to true after a successful drop for micro-feedback
   * @internal
   */
  isDropCompleted?: boolean;

  /**
   * Callback when drag enters folder (for syncing @dnd-kit state)
   * @internal
   */
  onDragEnter?: () => void;

  /**
   * Callback when drag leaves folder (for syncing @dnd-kit state)
   * @internal
   */
  onDragLeaveFolder?: () => void;
}

/**
 * CollapsibleFolder Section Styles
 *
 * Styles for the collapsible folder section.
 * Uses semantic tokens for AI-first compliance.
 */

.folder {
  background-color: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-container);
  padding: var(--spacing-6);
  margin-bottom: 0;
  transition:
    border-color var(--transition-fast),
    background-color var(--transition-fast),
    box-shadow var(--transition-fast);
}

/* Drop target visual */
.folder.dropTarget,
.folder[data-drop-active="true"] {
  border: 2px dashed var(--border-interactive);
  background-color: var(--soft-brand);
  filter: drop-shadow(0 0 0 2px var(--border-interactive));
  transition: all var(--transition-fast);
}

/* Micro-feedback: successful drop */
.folder.dropCompleted {
  border-color: var(--status-success);
  background-color: var(--surface-subtle);
}

/* Header section */
.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-4);
}

/* Collapsible trigger button */
.trigger {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  flex: 1;
  padding: 0;
  border: none;
  background: none;
  cursor: pointer;
  text-align: left;
  color: var(--text-primary);
  transition: color var(--transition-fast);
}

.trigger:hover {
  color: var(--interactive-primary);
}

.trigger:focus-visible {
  outline: 2px solid var(--interactive-primary);
  outline-offset: 2px;
  border-radius: var(--radius-control);
}

/* Chevron icon */
.chevron {
  flex-shrink: 0;
  transition: transform var(--transition-normal);
  color: var(--text-secondary);
}

.chevron.expanded {
  transform: rotate(0deg);
}

.chevron:not(.expanded) {
  transform: rotate(-90deg);
}

/* Folder title */
.title {
  font-family: var(--font-secondary);
  font-size: var(--font-size-18);
  font-weight: 600;
  color: var(--text-primary);
  margin: 0;
  line-height: 1.4;
}

/* Item count badge */
.badge {
  flex-shrink: 0;
}

/* Actions section (sort + menu) */
.actions {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
}

/* Content area (collapsible) */
.content {
  padding-top: var(--spacing-4);
  padding-bottom: var(--spacing-3);
}

/* Items grid */
.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--spacing-4);
}

/* Responsive grid */
@media (max-width: 1200px) {
  .grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 768px) {
  .grid {
    grid-template-columns: 1fr;
  }

  /* Badge: hide label text, show only the count */
  .badgeLabel {
    display: none;
  }

  /* Sort button: icon-only on mobile */
  .sortDropdown button > span:not([aria-hidden="true"]) {
    display: none;
  }

  .sortDropdown button {
    width: 32px;
    padding: 0;
  }
}

/* Empty state */
.emptyState {
  padding: var(--spacing-16) var(--spacing-8);
  text-align: center;
}

.emptyText {
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  color: var(--text-tertiary);
  margin: 0;
}

/* Insertion indicator: shows where the dragged item will be placed */
.insertionLine {
  height: 2px;
  background-color: var(--interactive-primary);
  border-radius: 1px;
  margin: var(--spacing-1) 0;
  position: relative;
  opacity: 1;

  /* Circular dot on the left edge */
  &::before {
    content: "";
    position: absolute;
    left: -6px;
    top: -3px;
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background-color: var(--interactive-primary);
  }
}

/* Empty drop zone for empty folders */
.emptyDropZone {
  padding: var(--spacing-4);
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 80px;
}

/* Reduced motion support */
@media (prefers-reduced-motion: reduce) {
  .folder {
    transition: none;
  }

  .chevron {
    transition: none;
  }
}

/**
 * CollapsibleFolder Section Exports
 *
 * Exports for the CollapsibleFolder section and its types.
 */

export { CollapsibleFolder } from "./CollapsibleFolder";
export type {
  CollapsibleFolderProps,
  SortOption,
} from "./CollapsibleFolder.types";
